using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// Shared state for the note-taking tool
var notebook = new ResearchNotebook();
using var searchTool = new WebSearchTool();

// Build the IChatClient through the MEAI abstraction
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Register tools the agent can invoke
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        searchTool.SearchAsync,
        name: "search_web",
        description: "Search the web for information on a topic. Returns relevant results with titles, snippets, and URLs."),
    AIFunctionFactory.Create(
        notebook.SaveNote,
        name: "save_note",
        description: "Save a research note for later reference. Use this to record key findings during research."),
    AIFunctionFactory.Create(
        notebook.GetNotes,
        name: "get_notes",
        description: "Retrieve all saved research notes to review what has been gathered so far."),
};

// Create the agent with instructions and tools
var agent = new ChatClientAgent(
    chatClient: chatClient,
    instructions: """
        You are a research agent. Your goal is to thoroughly research the given topic
        using the available tools.

        Follow this process:
        1. Search the web for the topic using multiple, varied queries to get broad coverage.
        2. Save important findings as notes using the save_note tool.
        3. Perform at least 3 different searches with different query angles.
        4. Review your saved notes using get_notes.
        5. Provide a comprehensive, well-organized summary of your findings.

        Be thorough but focused. Cite sources (URLs) when possible.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes",
    tools: tools);

// Get topic from the user
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// Run the agent with streaming output
var session = await agent.CreateSessionAsync("research");
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

var savedNotes = notebook.GetNotes();
if (savedNotes.Count > 0)
{
    Console.WriteLine($"\n📋 {savedNotes.Count} note(s) saved during research.\n");
}

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

/// <summary>Searches the web using the DuckDuckGo instant-answer API (no key required).</summary>
public sealed class WebSearchTool : IDisposable
{
    private readonly HttpClient _httpClient = new();

    public async Task<IReadOnlyList<SearchResult>> SearchAsync(
        [Description("The search query")] string query)
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        var results = new List<SearchResult>();

        try
        {
            using var response = await _httpClient.GetAsync(url);
            response.EnsureSuccessStatusCode();

            using var doc = await JsonDocument.ParseAsync(
                await response.Content.ReadAsStreamAsync());

            var root = doc.RootElement;

            // Main abstract (often from Wikipedia)
            if (root.TryGetProperty("Abstract", out var abs)
                && abs.GetString() is { Length: > 0 } abstractText)
            {
                var heading = root.TryGetProperty("Heading", out var h)
                    ? h.GetString() ?? query : query;
                var abstractUrl = root.TryGetProperty("AbstractURL", out var u)
                    ? u.GetString() ?? "" : "";

                results.Add(new SearchResult(heading, abstractText, abstractUrl));
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics)
                && topics.ValueKind == JsonValueKind.Array)
            {
                foreach (var item in topics.EnumerateArray())
                {
                    if (results.Count >= 6) break;

                    if (item.TryGetProperty("Text", out var text)
                        && text.GetString() is { Length: > 0 } snippet)
                    {
                        var itemUrl = item.TryGetProperty("FirstURL", out var fu)
                            ? fu.GetString() ?? "" : "";
                        var title = snippet.Length > 100
                            ? snippet[..100] + "…" : snippet;

                        results.Add(new SearchResult(title, snippet, itemUrl));
                    }
                }
            }
        }
        catch (HttpRequestException ex)
        {
            results.Add(new SearchResult(
                "Search error",
                $"Failed to search for '{query}': {ex.Message}",
                ""));
        }

        if (results.Count == 0)
        {
            results.Add(new SearchResult(
                "No results",
                $"No instant answers found for: {query}. Try a more specific query.",
                ""));
        }

        return results;
    }

    public void Dispose() => _httpClient.Dispose();
}

public record SearchResult(string Title, string Snippet, string Url);

/// <summary>In-memory notebook for saving and retrieving research notes.</summary>
public sealed class ResearchNotebook
{
    private readonly List<Note> _notes = [];

    public string SaveNote(
        [Description("Title or label for the note")] string title,
        [Description("Content of the note")] string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    public IReadOnlyList<Note> GetNotes() => _notes.AsReadOnly();
}

public record Note(string Title, string Content, DateTime SavedAt);

