using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// Shared state for the note-taking tool
var notebook = new ResearchNotebook();
using var searchTool = new WebSearchTool();

// Build the IChatClient through the MEAI abstraction
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Register tools the agent can invoke
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        searchTool.SearchAsync,
        name: "search_web",
        description: "Search the web for information on a topic. Returns relevant results with titles, snippets, and URLs."),
    AIFunctionFactory.Create(
        notebook.SaveNote,
        name: "save_note",
        description: "Save a research note for later reference. Use this to record key findings during research."),
    AIFunctionFactory.Create(
        notebook.GetNotes,
        name: "get_notes",
        description: "Retrieve all saved research notes to review what has been gathered so far."),
};

// Create the agent with instructions and tools
var agent = new ChatClientAgent(
    chatClient: chatClient,
    instructions: """
        You are a research agent. Your goal is to thoroughly research the given topic
        using the available tools.

        Follow this process:
        1. Search the web for the topic using multiple, varied queries to get broad coverage.
        2. Save important findings as notes using the save_note tool.
        3. Perform at least 3 different searches with different query angles.
        4. Review your saved notes using get_notes.
        5. Provide a comprehensive, well-organized summary of your findings.

        Be thorough but focused. Cite sources (URLs) when possible.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes",
    tools: tools);

// Get topic from the user
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// Run the agent with streaming output
var session = await agent.CreateSessionAsync("research");
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

var savedNotes = notebook.GetNotes();
if (savedNotes.Count > 0)
{
    Console.WriteLine($"\n📋 {savedNotes.Count} note(s) saved during research.\n");
}

